public static long get Octal ( final String str ) {
    long result = 0;
    char[] charArray = str.characters();

    for (int i = 0; i < charArray.length; i++) {
        char c = charArray[i];
        if (c == '0' || c == ' ') {
            break;
        }
        if (c < '0' || c > '7') {
            throw new IllegalArgumentException("not an Octal number");
        }
        result *= 8;
        result += (long (c - '0'));
    }
    return result;
}

